import{_ as e,p as c,q as d,a1 as i}from"./framework-96b046e1.js";const o={},l=i('<p>这里记录了我的一些 <code>KiCAD</code> 学习笔记。</p><h2 id="原理图快捷键" tabindex="-1"><a class="header-anchor" href="#原理图快捷键" aria-hidden="true">#</a> 原理图快捷键</h2><ul><li><code>a</code> 加载符号库</li><li><code>p</code> 加载电源符号库</li></ul><h2 id="添加器件" tabindex="-1"><a class="header-anchor" href="#添加器件" aria-hidden="true">#</a> 添加器件</h2><p>在添加器件对话框中输入器件名称即可搜到需要的器件，但是有时候又记不住器件名称，所以在此记录一下。</p><ul><li>电阻 <code>r</code></li><li>电容 <code>c</code> 有极性电容（<code>C_Polarized_Small</code>）</li><li>LED <code>led</code></li><li>二极管 <code>d diode</code> 或具体型号</li><li>三极管 <code>BJT</code> 或 具体型号</li><li>Mos 管 <code>NMOS</code></li><li>电感</li><li>自恢复</li><li>压敏电阻</li><li>热敏电阻</li><li>光耦 <code>optocoupler</code></li><li>达林顿管</li><li>继电器</li></ul><h2 id="pcb-过孔" tabindex="-1"><a class="header-anchor" href="#pcb-过孔" aria-hidden="true">#</a> PCB 过孔</h2><p>过孔（<code>via</code>）是<code>PCB</code>设计中的一个重要知识点，特别是对高速多层<code>PCB</code>设计来说，过孔的设计需要引起工程师的重视。</p><div class="custom-container tip"><p class="custom-container-title">过孔分类</p><ul><li>通孔</li><li>盲孔</li><li>埋孔</li></ul></div><p>过孔设计中的注意事项：</p><ul><li>过孔不能位于焊盘上</li><li>器件金属外壳与<code>PCB</code>接触区域向外延伸<code>1.5mm</code>区域内不能有过孔</li><li>贴片胶点涂或印刷区域内不能有过孔。如采用贴片胶点涂或印刷工艺的<code>CHIP</code>、<code>SOP</code>元件下方的<code>PCB</code>区域</li><li>全通过孔内径原则上要求<code>0.2mm</code>（8mil）及以上，外径的是<code>0.4mm</code>（16mil）以上，有困难地方必须控制在外径为<code>0.35mm</code>（14mil）</li><li><code>BGA</code>在<code>0.65mm</code>及以上的设计建议不要用到埋盲孔，成本会大幅度增加</li><li>过孔与过孔之间的间距不宜过近，钻孔容易引起破孔，一般要求孔间距<code>0.5mm</code>及以上，<code>0.35mm-0.4mm</code>极力避免，<code>0.3mm</code>及以下禁止</li></ul>',11),a=[l];function t(r,m){return c(),d("div",null,a)}const s=e(o,[["render",t],["__file","index.html.vue"]]);export{s as default};
